import { useState, useCallback, useMemo, useRef, useEffect } from "react";
import { createClient } from "@supabase/supabase-js";

// Supabase 設定
const SUPABASE_URL = "https://zhvxkxtzdzfwxptocwht.supabase.co";
const SUPABASE_KEY = "sb_publishable_2cB6778LUDI9r9gs-puYGg_mfafDpMj";
const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

// localStorage安全ラッパー（使えない環境では何もしない）
const LS = {
  get(key, fallback) {
    try {
      if (typeof localStorage === "undefined") return fallback;
      const v = localStorage.getItem(key);
      return v === null ? fallback : JSON.parse(v);
    } catch { return fallback; }
  },
  set(key, value) {
    try {
      if (typeof localStorage === "undefined") return;
      localStorage.setItem(key, JSON.stringify(value));
    } catch { /* 容量超過などは無視 */ }
  },
};
// 永続化付きuseState：初期値をlocalStorageから読み、変更時に自動保存
// Supabaseの英語エラーを日本語に
function translateAuthErr(msg) {
  const m = (msg || "").toLowerCase();
  if (m.includes("already registered") || m.includes("already been registered")) return "このメールアドレスは既に登録されています。ログインをお試しください。";
  if (m.includes("invalid login credentials")) return "メールアドレスまたはパスワードが違います。";
  if (m.includes("email not confirmed")) return "メール確認が完了していません。確認メールのリンクを開いてください。";
  if (m.includes("password should be")) return "パスワードは6文字以上にしてください。";
  if (m.includes("unable to validate email") || m.includes("invalid email")) return "メールアドレスの形式が正しくありません。";
  if (m.includes("rate limit") || m.includes("too many")) return "試行回数が多すぎます。少し時間をおいて再度お試しください。";
  return "エラーが発生しました：" + msg;
}

// ログイン/新規登録画面
function AuthScreen({ onAuthed }) {
  const [mode, setMode] = useState("login"); // "login" | "signup"
  const [email, setEmail] = useState("");
  const [pw, setPw] = useState("");
  const [pw2, setPw2] = useState("");
  const [err, setErr] = useState("");
  const [info, setInfo] = useState("");
  const [busy, setBusy] = useState(false);

  async function submit() {
    setErr("");
    const mail = email.trim().toLowerCase();
    if (!mail || !/^[^@]+@[^@]+\.[^@]+$/.test(mail)) { setErr("メールアドレスの形式が正しくありません。"); return; }
    if (pw.length < 6) { setErr("パスワードは6文字以上にしてください。"); return; }
    setBusy(true);
    try {
      if (mode === "signup") {
        if (pw !== pw2) { setErr("確認用パスワードが一致しません。"); setBusy(false); return; }
        const { data, error } = await supabase.auth.signUp({ email: mail, password: pw });
        if (error) { setErr(translateAuthErr(error.message)); setBusy(false); return; }
        // メール確認がオンの場合、セッションがまだ無いことがある
        if (!data.session) {
          setErr("");
          setInfo("確認メールを送信しました。メール内のリンクを開いてから、ログインしてください。");
          setMode("login");
          setBusy(false);
          return;
        }
        onAuthed(data.user);
      } else {
        const { data, error } = await supabase.auth.signInWithPassword({ email: mail, password: pw });
        if (error) { setErr(translateAuthErr(error.message)); setBusy(false); return; }
        onAuthed(data.user);
      }
    } catch (e) {
      setErr("通信エラーが発生しました。電波の良い場所で再度お試しください。");
    }
    setBusy(false);
  }

  return (
    <div className="auth-wrap">
      <div className="auth-card">
        <div className="auth-logo">宅建士 合格ナビ</div>
        <div className="auth-sub">{mode === "login" ? "ログイン" : "新規登録"}</div>
        <input className="auth-input" type="email" inputMode="email" autoComplete="email"
          placeholder="メールアドレス" value={email} onChange={e => setEmail(e.target.value)} />
        <input className="auth-input" type="password" autoComplete={mode === "login" ? "current-password" : "new-password"}
          placeholder="パスワード（4文字以上）" value={pw} onChange={e => setPw(e.target.value)} />
        {mode === "signup" && (
          <input className="auth-input" type="password" autoComplete="new-password"
            placeholder="パスワード（確認）" value={pw2} onChange={e => setPw2(e.target.value)} />
        )}
        {err && <div className="auth-err">{err}</div>}
        {info && <div className="auth-info">{info}</div>}
        <button className="auth-btn" onClick={submit} disabled={busy}>
          {busy ? "処理中…" : (mode === "login" ? "ログイン" : "登録して始める")}
        </button>
        <button className="auth-switch" onClick={() => { setErr(""); setInfo(""); setMode(mode === "login" ? "signup" : "login"); }}>
          {mode === "login" ? "アカウントをお持ちでない方はこちら（新規登録）" : "すでに登録済みの方はこちら（ログイン）"}
        </button>
        <div className="auth-note">※ ログイン情報はクラウドで安全に管理され、学習データも引き継がれます。</div>
      </div>
    </div>
  );
}

function usePersistentState(key, initial, { isSet = false } = {}) {
  const [state, setState] = useState(() => {
    const saved = LS.get(key, undefined);
    if (saved === undefined) return initial;
    return isSet ? new Set(saved) : saved;
  });
  useEffect(() => {
    LS.set(key, isSet ? [...state] : state);
  }, [key, state, isSet]);
  return [state, setState];
}

