// 年度ごとの問番号マップ（年度内でid昇順に第1問・第2問…と採番）
const QUESTION_NO_MAP = (() => {
  const byYear = {};
  QUESTIONS.forEach(q => {
    (byYear[q.year] = byYear[q.year] || []).push(q);
  });
  const map = {};
  Object.values(byYear).forEach(arr => {
    arr.sort((a, b) => a.id - b.id).forEach((q, i) => { map[q.id] = i + 1; });
  });
  return map;
})();

