// 年度一覧を動的生成
function getYears() {
  const ys = [...new Set(QUESTIONS.map(q => q.year))].sort((a, b) => {
    const toNum = y => {
      // 数字部分と月情報を抽出（例: "R2(10月)" → 元号R, 年2, 月10）
      const era = y[0];
      const mNum = y.match(/\d+/); // 最初の数字（年）
      const yearNum = mNum ? parseInt(mNum[0]) : 0;
      let base = 0;
      if (era === "R") base = 2018 + yearNum;
      else if (era === "H") base = 1988 + yearNum;
      // 同じ年の中で月で並べる（12月 > 10月）
      const monthMatch = y.match(/\((\d+)月\)/);
      const month = monthMatch ? parseInt(monthMatch[1]) : 0;
      return base * 100 + month;
    };
    return toNum(b) - toNum(a);
  });
  return ys;
}

// 4択用ダミー選択肢生成（同じ科目から3問ランダムに誤り選択肢を作る）
function make4Choices(q, allQs) {
  const correct = { text: q.text, isCorrect: true, answer: q.answer, explanation: q.explanation };
  // 同科目の他問題から3問選ぶ
  const pool = allQs.filter(qq => qq.id !== q.id && qq.subject === q.subject);
  const shuffled = [...pool].sort(() => Math.random() - 0.5).slice(0, 3);
  const wrong = shuffled.map(qq => ({ text: qq.text, isCorrect: false, answer: qq.answer, explanation: qq.explanation }));
  // 全4択をシャッフル
  const choices = [correct, ...wrong].sort(() => Math.random() - 0.5);
  return choices;
}

